seedUsers();

// GraphQL Schema
const typeDefs = gql`
  enum UserRole {
    ADMIN
    MODERATOR
    USER
  }

  enum UserStatus {
    ACTIVE
    INACTIVE
    SUSPENDED
  }

  enum SortField {
    USERNAME
    EMAIL
    FIRST_NAME
    LAST_NAME
    CREATED_AT
    UPDATED_AT
  }

  enum SortOrder {
    ASC
    DESC
  }

  type User {
    id: ID!
    username: String!
    email: String!
    firstName: String!
    lastName: String!
    fullName: String!
    role: UserRole!
    status: UserStatus!
    createdAt: String!
    updatedAt: String!
  }

  type UserBatchResult {
    found: [User!]!
    notFoundIds: [ID!]!
    totalRequested: Int!
    totalFound: Int!
  }

  type UserConnection {
    users: [User!]!
    totalCount: Int!
    pageInfo: PageInfo!
  }

  type PageInfo {
    hasNextPage: Boolean!
    hasPreviousPage: Boolean!
    currentPage: Int!
    totalPages: Int!
  }

  type DashboardStats {
    totalUsers: Int!
    activeUsers: Int!
    inactiveUsers: Int!
    suspendedUsers: Int!
    adminCount: Int!
    moderatorCount: Int!
    regularUserCount: Int!
  }

  type BulkOperationResult {
    successIds: [ID!]!
    failedIds: [ID!]!
    totalProcessed: Int!
    totalSuccess: Int!
    totalFailed: Int!
  }

  input UserFilterInput {
    roles: [UserRole!]
    statuses: [UserStatus!]
    searchTerm: String
  }

  input SortInput {
    field: SortField!
    order: SortOrder!
  }

  input CreateUserInput {
    username: String!
    email: String!
    firstName: String!
    lastName: String!
    role: UserRole
    status: UserStatus
  }

  input UpdateUserInput {
    username: String
    email: String
    firstName: String
    lastName: String
    role: UserRole
    status: UserStatus
  }

  input BulkCreateUserInput {
    username: String!
    email: String!
    firstName: String!
    lastName: String!
    role: UserRole
    status: UserStatus
  }

  type Query {
    # Single user query
    user(id: ID!): User

    # Batch query - fetch multiple users by IDs array (reduces round trips)
    users(ids: [ID!]!): UserBatchResult!

    # Paginated and filtered user listing for dashboard
    userList(
      page: Int
      pageSize: Int
      filter: UserFilterInput
      sort: SortInput
    ): UserConnection!

    # Fetch users by role (array-based)
    usersByRoles(roles: [UserRole!]!): [User!]!

    # Fetch users by status (array-based)
    usersByStatuses(statuses: [UserStatus!]!): [User!]!

    # Fetch users by emails (array-based bulk lookup)
    usersByEmails(emails: [String!]!): UserBatchResult!

    # Fetch users by usernames (array-based bulk lookup)
    usersByUsernames(usernames: [String!]!): UserBatchResult!

    # Dashboard statistics
    dashboardStats: DashboardStats!

    # Search users
    searchUsers(term: String!, limit: Int): [User!]!
  }

  type Mutation {
    # Create a single user
    createUser(input: CreateUserInput!): User!

    # Bulk create users (array-based)
    bulkCreateUsers(inputs: [BulkCreateUserInput!]!): [User!]!

    # Update a single user
    updateUser(id: ID!, input: UpdateUserInput!): User

    # Bulk update user status (array-based)
    bulkUpdateUserStatus(ids: [ID!]!, status: UserStatus!): BulkOperationResult!

    # Bulk update user roles (array-based)
    bulkUpdateUserRole(ids: [ID!]!, role: UserRole!): BulkOperationResult!

    # Delete a single user
    deleteUser(id: ID!): Boolean!

    # Bulk delete users (array-based)
    bulkDeleteUsers(ids: [ID!]!): BulkOperationResult!
  }
`;

// Resolvers
const resolvers = {
  User: {
    fullName: (parent) => `${parent.firstName} ${parent.lastName}`,
  },

  Query: {
    // Single user fetch
    user: (_, { id }) => {
      return users.get(id) || null;
    },

    // Batch fetch users by IDs - the core array-based query
    users: (_, { ids }) => {
      const found = [];
      const notFoundIds = [];

      // Deduplicate IDs
      const uniqueIds = [...new Set(ids)];

      for (const id of uniqueIds) {
        const user = users.get(id);
        if (user) {
          found.push(user);
        } else {
          notFoundIds.push(id);
        }
      }

      return {
        found,
        notFoundIds,
        totalRequested: uniqueIds.length,
        totalFound: found.length,
      };
    },

    // Paginated user listing with filtering and sorting
    userList: (_, { page = 1, pageSize = 10, filter, sort }) => {
      let allUsers = Array.from(users.values());

      // Apply filters
      if (filter) {
        if (filter.roles && filter.roles.length > 0) {
          allUsers = allUsers.filter(u => filter.roles.includes(u.role));
        }
        if (filter.statuses && filter.statuses.length > 0) {
          allUsers = allUsers.filter(u => filter.statuses.includes(u.status));
        }
        if (filter.searchTerm) {
          const term = filter.searchTerm.toLowerCase();
          allUsers = allUsers.filter(u =>
            u.username.toLowerCase().includes(term) ||
            u.email.toLowerCase().includes(term) ||
            u.firstName.toLowerCase().includes(term) ||
            u.lastName.toLowerCase().includes(term)
          );
        }
      }

      // Apply sorting
      if (sort) {
        const fieldMap = {
          USERNAME: 'username',
          EMAIL: 'email',
          FIRST_NAME: 'firstName',
          LAST_NAME: 'lastName',
          CREATED_AT: 'createdAt',
          UPDATED_AT: 'updatedAt',
        };
        const field = fieldMap[sort.field];
        const multiplier = sort.order === 'ASC' ? 1 : -1;

        allUsers.sort((a, b) => {
          if (a[field] < b[field]) return -1 * multiplier;
          if (a[field] > b[field]) return 1 * multiplier;
          return 0;
        });
      }

      const totalCount = allUsers.length;
      const totalPages = Math.ceil(totalCount / pageSize);
      const startIndex = (page - 1) * pageSize;
      const paginatedUsers = allUsers.slice(startIndex, startIndex + pageSize);

      return {
        users: paginatedUsers,
        totalCount,
        pageInfo: {
          hasNextPage: page < totalPages,
          hasPreviousPage: page > 1,
          currentPage: page,
          totalPages,
        },
      };
    },

    // Fetch users by multiple roles
    usersByRoles: (_, { roles }) => {
      return Array.from(users.values()).filter(u => roles.includes(u.role));
    },

    // Fetch users by multiple statuses
    usersByStatuses: (_, { statuses }) => {
      return Array.from(users.values()).filter(u => statuses.includes(u.status));
    },

    // Bulk lookup by emails
    usersByEmails: (_, { emails }) => {
      const uniqueEmails = [...new Set(emails.map(e => e.toLowerCase()))];
      const emailToUser = new Map();
      for (const user of users.values()) {
        emailToUser.set(user.email.toLowerCase(), user);
      }

      const found = [];
      const notFoundIds = [];

      for (const email of uniqueEmails) {
        const user = emailToUser.get(email);
        if (user) {
          found.push(user);
        } else {
          notFoundIds.push(email);
        }
      }

      return {
        found,
        notFoundIds,
        totalRequested: uniqueEmails.length,
        totalFound: found.length,
      };
    },

    // Bulk lookup by usernames
    usersByUsernames: (_, { usernames }) => {
      const uniqueUsernames = [...new Set(usernames.map(u => u.toLowerCase()))];
      const usernameToUser = new Map();
      for (const user of users.values()) {
        usernameToUser.set(user.username.toLowerCase(), user);
      }

      const found = [];
      const notFoundIds = [];

      for (const username of uniqueUsernames) {
        const user = usernameToUser.get(username);
        if (user) {
          found.push(user);
        } else {
          notFoundIds.push(username);
        }
      }

      return {
        found,
        notFoundIds,
        totalRequested: uniqueUsernames.length,
        totalFound: found.length,
      };
    },

    // Dashboard statistics
    dashboardStats: () => {
      const allUsers = Array.from(users.values());
      return {
        totalUsers: allUsers.length,
        activeUsers: allUsers.filter(u => u.status === 'ACTIVE').length,
        inactiveUsers: allUsers.filter(u => u.status === 'INACTIVE').length,
        suspendedUsers: allUsers.filter(u => u.status === 'SUSPENDED').length,
        adminCount: allUsers.filter(u => u.role === 'ADMIN').length,
        moderatorCount: allUsers.filter(u => u.role === 'MODERATOR').length,
        regularUserCount: allUsers.filter(u => u.role === 'USER').length,
      };
    },

    // Search users
    searchUsers: (_, { term, limit = 20 }) => {
      const lowerTerm = term.toLowerCase();
      const results = Array.from(users.values()).filter(u =>
        u.username.toLowerCase().includes(lowerTerm) ||
        u.email.toLowerCase().includes(lowerTerm) ||
        u.firstName.toLowerCase().includes(lowerTerm) ||
        u.lastName.toLowerCase().includes(lowerTerm)
      );
      return results.slice(0, limit);
    },
  },

  Mutation: {
    // Create a single user
    createUser: (_, { input }) => {
      // Check for duplicate username
      const existingByUsername = Array.from(users.values()).find(
        u => u.username.toLowerCase() === input.username.toLowerCase()
      );
      if (existingByUsername) {
        throw new Error(`Username '${input.username}' already exists`);
      }

      // Check for duplicate email
      const existingByEmail = Array.from(users.values()).find(
        u => u.email.toLowerCase() === input.email.toLowerCase()
      );
      if (existingByEmail) {
        throw new Error(`Email '${input.email}' already exists`);
      }

      const now = new Date().toISOString();
      const newUser = {
        id: uuidv4(),
        username: input.username,
        email: input.email,
        firstName: input.firstName,
        lastName: input.lastName,
        role: input.role || 'USER',
        status: input.status || 'ACTIVE',
        createdAt: now,
        updatedAt: now,
      };

      users.set(newUser.id, newUser);
      return newUser;
    },

    // Bulk create users
    bulkCreateUsers: (_, { inputs }) => {
      const createdUsers = [];
      const now = new Date().toISOString();

      // Collect existing usernames and emails for validation
      const existingUsernames = new Set(
        Array.from(users.values()).map(u => u.username.toLowerCase())
      );
      const existingEmails = new Set(
        Array.from(users.values()).map(u => u.email.toLowerCase())
      );

      for (const input of inputs) {
        if (existingUsernames.has(input.username.toLowerCase())) {
          throw new Error(`Username '${input.username}' already exists`);
        }
        if (existingEmails.has(input.email.toLowerCase())) {
          throw new Error(`Email '${input.email}' already exists`);
        }

        const newUser = {
          id: uuidv4(),
          username: input.username,
          email: input.email,
          firstName: input.firstName,
          lastName: input.lastName,
          role: input.role || 'USER',
          status: input.status || 'ACTIVE',
          createdAt: now,
          updatedAt: now,
        };

        users.set(newUser.id, newUser);
        createdUsers.push(newUser);

        // Track newly added for duplicate detection within the batch
        existingUsernames.add(input.username.toLowerCase());
        existingEmails.add(input.email.toLowerCase());
      }

      return createdUsers;
    },

    // Update a single user
    updateUser: (_, { id, input }) => {
      const user = users.get(id);
      if (!user) return null;

      // Check for duplicate username if updating
      if (input.username) {
        const existingByUsername = Array.from(users.values()).find(
          u => u.username.toLowerCase() === input.username.toLowerCase() && u.id !== id
        );
        if (existingByUsername) {
          throw new Error(`Username '${input.username}' already exists`);
        }
      }

      // Check for duplicate email if updating
      if (input.email) {
        const existingByEmail = Array.from(users.values()).find(
          u => u.email.toLowerCase() === input.email.toLowerCase() && u.id !== id
        );
        if (existingByEmail) {
          throw new Error(`Email '${input.email}' already exists`);
        }
      }

      const updatedUser = {
        ...user,
        ...Object.fromEntries(
          Object.entries(input).filter(([_, v]) => v !== undefined && v !== null)
        ),
        updatedAt: new Date().toISOString(),
      };

      users.set(id, updatedUser);
      return updatedUser;
    },

    // Bulk update user status
    bulkUpdateUserStatus: (_, { ids, status }) => {
      const uniqueIds = [...new Set(ids)];
      const successIds = [];
      const failedIds = [];
      const now = new Date().toISOString();

      for (const id of uniqueIds) {
        const user = users.get(id);
        if (user) {
          user.status = status;
          user.updatedAt = now;
          users.set(id, user);
          successIds.push(id);
        } else {
          failedIds.push(id);
        }
      }

      return {
        successIds,
        failedIds,
        totalProcessed: uniqueIds.length,
        totalSuccess: successIds.length,
        totalFailed: failedIds.length,
      };
    },

    // Bulk update user roles
    bulkUpdateUserRole: (_, { ids, role }) => {
      const uniqueIds = [...new Set(ids)];
      const successIds = [];
      const failedIds = [];
      const now = new Date().toISOString();

      for (const id of uniqueIds) {
        const user = users.get(id);
        if (user) {
          user.role = role;
          user.updatedAt = now;
          users.set(id, user);
          successIds.push(id);
        } else {
          failedIds.push(id);
        }
      }

      return {
        successIds,
        failedIds,
        totalProcessed: uniqueIds.length,
        totalSuccess: successIds.length,
        totalFailed: failedIds.length,
      };
    },

    // Delete a single user
    deleteUser: (_, { id }) => {
      if (!users.has(id)) return false;
      users.delete(id);
      return true;
    },

    // Bulk delete users
    bulkDeleteUsers: (_, { ids }) => {
      const uniqueIds = [...new Set(ids)];
      const successIds = [];
      const failedIds = [];

      for (const id of uniqueIds) {
        if (users.has(id)) {
          users.delete(id);
          successIds.push(id);
        } else {
          failedIds.push(id);
        }
      }

      return {
        successIds,
        failedIds,
        totalProcessed: uniqueIds.length,
        totalSuccess: successIds.length,
        totalFailed: failedIds.length,
      };
    },
  },
};

// Create and start the server
const server = new ApolloServer({
  typeDefs,
  resolvers,
  introspection: true,
  plugins: [
    {
      requestDidStart() {
        const start = Date.now();
        return {
          willSendResponse() {
            const duration = Date.now() - start;
            console.log(`Request completed in ${duration}ms`);
          },
        };
      },
    },
  ],
});

